{
  "terms": [
    {
      "term": "TT Earthing System",
      "simpleDefinition": "An earthing arrangement where the consumer provides their own connection to Earth, usually via a rod in the ground.",
      "anchor": "The 'Earth Electrode' system.",
      "misconception": "Thinking the supplier provides the earth path in a TT system; they do not."
    },
    {
      "term": "TN-S Earthing System",
      "simpleDefinition": "An earthing arrangement where the supplier provides a separate earth conductor (usually the cable sheath) all the way from the transformer.",
      "anchor": "TN-S = Separate (S for Separate).",
      "misconception": "Confusing the separate earth conductor with the neutral conductor."
    },
    {
      "term": "TN-C-S Earthing System",
      "simpleDefinition": "An earthing arrangement where the neutral and earth are combined in the supply cable but separated at the consumer's intake.",
      "anchor": "TN-C-S = Combined then Separate.",
      "misconception": "Believing the earth and neutral stay combined throughout the entire installation."
    },
    {
      "term": "ADS (Automatic Disconnection of Supply)",
      "simpleDefinition": "A safety method that uses earthing and protective devices to quickly cut off power during a fault.",
      "anchor": "The 'Trip' system for safety.",
      "misconception": "Thinking ADS is a single part; it is actually a system of conductors and devices working together."
    },
    {
      "term": "CPC (Circuit Protective Conductor)",
      "simpleDefinition": "The specific wire in a circuit that connects metal parts to the main earthing terminal.",
      "anchor": "The circuit's own earth wire.",
      "misconception": "Using the term 'earth' for everything; the CPC is specifically the wire within the final circuit."
    },
    {
      "term": "Main Protective Bonding",
      "simpleDefinition": "Conductors that connect metal service pipes (like gas or water) to the main earthing terminal.",
      "anchor": "Connecting services to stop voltage differences.",
      "misconception": "Thinking bonding is meant to carry fault current like an earth wire; its job is to keep metal parts at the same voltage."
    },
    {
      "term": "Earthing Conductor",
      "simpleDefinition": "The main cable that connects the installation's main earthing terminal to the supplier's earth or an electrode.",
      "anchor": "The master link to the Earth.",
      "misconception": "Confusing the main earthing conductor with the smaller CPCs used in individual circuits."
    },
    {
      "term": "Protective Device",
      "simpleDefinition": "A component such as a fuse, MCB, or RCD that automatically breaks the circuit during a fault.",
      "anchor": "The fuse or circuit breaker.",
      "misconception": "Thinking the earth wire alone protects you; the protective device must trip to actually stop the danger."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A metal rod or plate driven into the ground to create a physical connection to Earth.",
      "anchor": "The rod in the soil.",
      "misconception": "Thinking every house has an electrode; they are primarily used in TT systems."
    }
  ],
  "anchorPhrases": [
    "TT uses an electrode.",
    "TN-S has a separate earth.",
    "TN-C-S combines then separates.",
    "ADS requires both a path and a device.",
    "Bonding is for pipes; Earthing is for circuits."
  ],
  "misconceptionTargets": [
    "Earthing and bonding are the same thing.",
    "All earthing systems use an earth electrode at the property.",
    "The earth wire alone provides protection without a protective device.",
    "Terms like CPC and Earthing Conductor are interchangeable."
  ]
}

{
  "teachChecks": [
    {
      "title": "Earthing System Types",
      "objective": "Identify and distinguish between TT, TN-S, and TN-C-S earthing systems.",
      "retrievalTextLines": [
        "In electrical installations, earthing systems are identified by letter codes that describe how the installation is connected to the ground. The first letter 'T' stands for Terre (Earth), indicating the supply source is connected to the ground. The second letter 'N' stands for Neutral.",
        "In a TT system, the consumer must provide their own connection to Earth using an Earth Electrode, which is typically a metal rod driven into the soil. The supplier does not provide an earth return path in this arrangement.",
        "In a TN-S system, the 'S' stands for Separate. The supplier provides a dedicated earth conductor, such as the metal sheath of the supply cable, which remains separate from the neutral conductor all the way from the transformer to the property.",
        "In a TN-C-S system, the 'C' stands for Combined and 'S' for Separate. The neutral and earth are combined into a single conductor in the supplier's street cables but are separated into two distinct terminals once they reach the consumer's intake point."
      ],
      "hint": "Focus on what the S (Separate) and C (Combined) stand for in the TN systems to understand how the conductors are arranged."
    },
    {
      "title": "ADS Component Parts",
      "objective": "Identify the specific components that facilitate Automatic Disconnection of Supply.",
      "retrievalTextLines": [
        "Automatic Disconnection of Supply (ADS) is a safety method designed to cut off power instantly during a fault to prevent electric shock. For ADS to work, there must be a complete path for fault current and a Protective Device, such as a Miniature Circuit Breaker (MCB) or Residual Current Device (RCD), to detect the fault and trip the circuit.",
        "The Earthing Conductor is the main cable that links the entire installation to the supplier's earth terminal or an earth electrode. Within individual circuits, the Circuit Protective Conductor (CPC) is the specific wire that connects metal equipment to the earthing system.",
        "Main Protective Bonding is used to connect metal service pipes, like gas and water, to the main earthing terminal. This is done to ensure all metal parts stay at the same voltage (equipotential), which prevents a person from getting a shock if they touch two different metal surfaces at once. Supplementary bonding provides additional protection in high-risk areas like bathrooms."
      ],
      "hint": "Remember that the CPC is for individual circuits, while the Earthing Conductor is the main link for the whole building."
    }
  ]
}

